import type { ProductDTO } from '@smartcart/shared-types';

/**
 * Catalog port (README §2.8 Workflow 4 step 2). Consumed by the Checkout module
 * to resolve a scanned barcode → product (with its `pointsConfig`). Bound to the
 * concrete `CatalogService` in `CatalogModule` and exported for cross-module DI.
 */
export const CATALOG_SERVICE = 'ICatalogService';

export interface ICatalogService {
  /** Cache-Aside lookup; throws NotFoundException when the barcode is unknown. */
  getByBarcode(barcode: string): Promise<ProductDTO>;
}
